/** @type {import('../../..').TextfieldMask} */
export default {
  mask: 'X',
  tokens: {
    X: { pattern: /[\dkK]/, multiple: true },
  },
  eager: true,
  preProcess: (val) => val.replace(/[^\dkK]/gi, '').slice(0, 9),
  postProcess: (rawInput) => {
    if (!rawInput) return '';

    const sanitized = rawInput
      .replace(/[^0-9kK]/g, '')
      .toUpperCase()
      .replace(/^0+/, '');

    if (!sanitized) return '';

    if (sanitized.length < 8) {
      const [, part1 = '', part2 = '', part3 = ''] = sanitized.match(/^(\d{1,2})(\d{0,3})?(\d{0,3})?/) || [];
      return [part1, part2, part3].filter(Boolean).join('.');
    }

    const numberPart = sanitized.slice(0, -1);
    const verifier = sanitized.slice(-1);

    return `${numberPart.replace(/^(\d{1,2})(\d{3})(\d{3})$/, '$1.$2.$3')}-${verifier}`;
  },
};
