/** @type {import('../../..').TextfieldMask} */
export default {
  mask: 'C-DDDDDDDD-D',
  eager: true,
  tokens: {
    C: { pattern: /[VEJGEP]/ },
    D: { pattern: /\d/ },
  },
  preProcess: (val) => {
    const upper = val.toUpperCase().replace(/[^A-Z0-9]/g, '');

    const firstChar = upper.charAt(0);
    if (!/[VEJGEP]/.test(firstChar)) {
      return '';
    }

    const digits = upper.slice(1).replace(/\D/g, '');
    return (firstChar + digits).slice(0, 10);
  },
};
