import { validateDateTime } from '../../utils';

/** @type {import('../../..').TextfieldMask} */
export default {
  mask: 'DD/DD/DDDD DD:DD:DD',
  tokens: {
    D: { pattern: /\d/ },
  },
  eager: true,
  preProcess: (value) => value.replace(/[^\d/:]/g, ''),
  postProcess: (value) => validateDateTime(value),
};
